<?php
require __DIR__.'/config.php';require_admin();$id=(int)($_GET['id']??$_POST['id']??0);$stmt=db()->prepare("SELECT id,name,email,role,active FROM users WHERE id=? AND role='User'");$stmt->execute([$id]);$target=$stmt->fetch();if(!$target){http_response_code(404);exit('Düzenlenebilir User kullanıcısı bulunamadı.');}$key='profile_'.$id;$p=db()->prepare('SELECT setting_value FROM settings WHERE setting_key=?');$p->execute([$key]);$profile=json_decode((string)$p->fetchColumn(),true)?:[];$profile=array_merge(['phone'=>'','organization'=>'','address'=>'','state'=>'','zip_code'=>'','country'=>'Türkiye','language'=>'Türkçe','timezone'=>'Europe/Istanbul','currency'=>'TRY','avatar'=>''],$profile);$message='';$error='';
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=$_POST['action']??'';
 if($action==='profile'){$name=trim($_POST['name']??'');$email=trim(strtolower($_POST['email']??''));$active=isset($_POST['active'])?1:0;if($name===''||!filter_var($email,FILTER_VALIDATE_EMAIL))$error='Geçerli ad ve e-posta girin.';else{$check=db()->prepare('SELECT id FROM users WHERE LOWER(email)=LOWER(?) AND id<>? LIMIT 1');$check->execute([$email,$id]);if($check->fetch())$error='Bu e-posta adresi başka bir kullanıcı tarafından kullanılıyor. Aynı e-posta ile ikinci kullanıcı olamaz.';else try{$update=db()->prepare("UPDATE users SET name=?,email=?,active=? WHERE id=? AND role='User'");$update->execute([$name,$email,$active,$id]);foreach(['phone','organization','address','state','zip_code','country','language','timezone','currency'] as $field)$profile[$field]=trim($_POST[$field]??'');$driver=db()->getAttribute(PDO::ATTR_DRIVER_NAME);$sql=$driver==='mysql'?'INSERT INTO settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)':'INSERT INTO settings(setting_key,setting_value) VALUES(?,?) ON CONFLICT(setting_key) DO UPDATE SET setting_value=excluded.setting_value';db()->prepare($sql)->execute([$key,json_encode($profile,JSON_UNESCAPED_UNICODE)]);$target['name']=$name;$target['email']=$email;$target['active']=$active;$message='Kullanıcı profili güncellendi.';}catch(PDOException $e){$error='Bu e-posta adresi başka bir kullanıcı tarafından kullanılıyor. Aynı e-posta ile ikinci kullanıcı olamaz.';}}}
 if($action==='password'){$password=$_POST['password']??'';$confirm=$_POST['password_confirm']??'';if(strlen($password)<6)$error='Şifre en az 6 karakter olmalıdır.';elseif($password!==$confirm)$error='Şifre ve şifre tekrarı aynı olmalıdır.';else{$update=db()->prepare("UPDATE users SET password_hash=? WHERE id=? AND role='User'");$update->execute([password_hash($password,PASSWORD_DEFAULT),$id]);$message='Kullanıcının şifresi değiştirildi.';}}
}
?>
<!doctype html><html lang="tr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Kullanıcı Düzenle | <?=APP_NAME?></title><link rel="icon" href="<?=url('assets/favicon.png')?>"><link rel="stylesheet" href="<?=url('assets/style.css')?>"><link rel="stylesheet" href="<?=url('assets/admin.css')?>"><link rel="stylesheet" href="<?=url('assets/profile.css')?>"><link rel="stylesheet" href="<?=url('assets/green-buttons.css?v=20260712-4')?>"><script src="<?=url('assets/theme.js?v=20260712-2')?>"></script></head><body><header><div class="brand"><span class="brand-mark">K</span><span>KRP <b>Lost &amp; Found</b></span></div><a class="button secondary" href="<?=url('admin.php#kullanicilar')?>">Kullanıcılara dön</a></header><main class="profile-container"><section class="title-row"><div><h1><?=e($target['name'])?></h1><p>User profilini ve giriş şifresini yönetin.</p></div></section><?php if($message):?><div class="success"><?=e($message)?></div><?php endif?><?php if($error):?><div class="alert"><?=e($error)?></div><?php endif?><section class="profile-card"><h2>Profil Bilgileri</h2><form class="profile-form" method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="action" value="profile"><label>Ad Soyad<input name="name" value="<?=e($target['name'])?>" required></label><label>E-posta<input type="email" name="email" value="<?=e($target['email'])?>" required></label><label>Telefon<input name="phone" value="<?=e($profile['phone'])?>"></label><label>Kurum<input name="organization" value="<?=e($profile['organization'])?>"></label><label>Adres<input name="address" value="<?=e($profile['address'])?>"></label><label>Şehir / İl<input name="state" value="<?=e($profile['state'])?>"></label><label>Posta Kodu<input name="zip_code" value="<?=e($profile['zip_code'])?>"></label><label>Ülke<input name="country" value="<?=e($profile['country'])?>"></label><label>Dil<input name="language" value="<?=e($profile['language'])?>"></label><label>Saat Dilimi<input name="timezone" value="<?=e($profile['timezone'])?>"></label><label>Para Birimi<input name="currency" value="<?=e($profile['currency'])?>"></label><label class="active-user"><input type="checkbox" name="active" value="1" <?=$target['active']?'checked':''?>> Kullanıcı aktif</label><div class="profile-actions"><button class="save-profile">Kaydet</button></div></form></section><section class="profile-card password-card"><h2>Şifre Değiştir</h2><form class="password-form" method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="id" value="<?=$id?>"><input type="hidden" name="action" value="password"><label>Yeni şifre<input type="password" name="password" minlength="6" autocomplete="new-password" required></label><label>Yeni şifre tekrar<input type="password" name="password_confirm" minlength="6" autocomplete="new-password" required></label><button class="save-profile">Kaydet</button></form></section></main></body></html>
